         $start_day = $2;
         $start_hr = $3;
         $start_min = $4;
         $start_year = $5;
         $start_found = 1;
     } elsif ($line =~ m/^CPU Time:/) {
         $expect_end_time_next = 1;
     } elsif ($expect_end_time_next) {
