     $total_time = (($endseconds - $startseconds) / 60) / 60;
     $total_time_string = sprintf(": runtime was approximately %.2f hours",$total_time);
  }

   # Add other checks of the log file as it becomes necessary

   close(FH);

   my $dumpdiff_passed = 1;
